SELECT cs.semester_type AS semester, cs.academic_year AS academic_year, COUNT(e.id) AS enrollment_count FROM public.enrollments e JOIN public.course_sections cs ON e.course_section_id = cs.id WHERE e.is_active = true AND cs.semester_type IS NOT NULL AND cs.academic_year IS NOT NULL GROUP BY cs.semester_type, cs.academic_year ORDER BY cs.academic_year ASC, cs.semester_type ASC;